public class Main {
    public static void main(String[] args) {
        int temperature = 30;
        if (temperature >= 25) {
            System.out.println("hot");
        } else {
            System.out.println("mild");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        int code = 1234;
        if (code == 1234) {
            System.out.println("unlocked");
        } else {
            System.out.println("denied");
        }
    }
}

